args.sparql:
SELECT DISTINCT ?winner ?winnerLabel ?date
WHERE {
  wd:Q208730 wdt:P361 ?edition .
  ?edition wdt:P1545 ?winner .
  ?edition wdt:P585 ?date .
  {
    ?winner wdt:P27 wd:Q30
  }
  UNION
  {
    ?winner wdt:P19 ?birthPlace .
    ?birthPlace wdt:P17 wd:Q30
  }
}
ORDER BY DESC(?date)
LIMIT 1
